#include<bits/stdc++.h>
using namespace std;
constexpr long long nulltag=1145141919;
mt19937 rnd;
struct FHQ_Treap
{
    struct node
    {
        long long l,r;
        long long val,key;
        long long sum,maxl,maxr,ans;
        long long siz,rev_tag,upd_tag;
        node():l(0),r(0),val(0),sum(0),key(0),maxl(0),maxr(0),ans(0),siz(0),rev_tag(0),upd_tag(0){}
    }t[500010];
    long long cnt,root;
    stack<long long> s;
    FHQ_Treap():cnt(0)
    {
        t[0].sum=0;
        t[0].maxl=t[0].maxr=0;
        t[0].ans=-1e18;
    }
    long long newnode(long long v)
    {
        long long x;
        if(!s.empty())
        {
            x=s.top();
            s.pop();
        }
        else
        {
            x=++cnt;
        }
        t[x].l=t[x].r=0;
        t[x].val=t[x].sum=t[x].ans=v;
        t[x].maxl=t[x].maxr=max(0ll,v);
        t[x].key=rnd();
        t[x].siz=1;
        t[x].rev_tag=0;
        t[x].upd_tag=nulltag;
        return x;
    }
    void pushup(long long x)
    {
        // if(t[x].l==0&&t[x].r==0)
        // {
        //     t[x].siz=1;
        //     t[x].sum=t[x].ans=t[x].val;
        //     t[x].maxl=t[x].maxr=max(0ll,t[x].val);
        //     return;
        // }
        // if(t[x].l==0)
        // {
        //     t[x].siz=t[t[x].r].siz+1;
        //     t[x].sum=t[t[x].r].sum+t[x].val;
        //     t[x].maxl=max({0ll,t[t[x].r].maxl+t[x].val});
        //     t[x].maxr=max({0ll,t[x].sum,t[t[x].r].maxr});
        //     t[x].ans=max(t[t[x].r].ans,t[x].val+t[t[x].r].maxl);
        //     return;
        // }
        // if(t[x].r==0)
        // {
        //     t[x].siz=t[t[x].l].siz+1;
        //     t[x].sum=t[t[x].l].sum+t[x].val;
        //     t[x].maxl=max({0ll,t[t[x].l].maxl,t[x].sum});
        //     t[x].maxr=max({0ll,t[t[x].l].maxr+t[x].val});
        //     t[x].ans=max(t[t[x].l].ans,t[t[x].l].maxr+t[x].val);
        //     return;
        // }
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
        t[x].sum=t[t[x].l].sum+t[t[x].r].sum+t[x].val;
        t[x].maxl=max({0ll,t[t[x].l].maxl,t[t[x].l].sum+t[x].val+t[t[x].r].maxl});
        t[x].maxr=max({0ll,t[t[x].r].maxr,t[t[x].l].maxr+t[x].val+t[t[x].r].sum});
        t[x].ans=max({t[t[x].l].ans,t[t[x].r].ans,t[t[x].l].maxr+t[x].val+t[t[x].r].maxl});
    }
    void pushrev(long long x)
    {
        if(x==0)
        {
            return;
        }
        swap(t[x].l,t[x].r);
        swap(t[x].maxl,t[x].maxr);
        t[x].rev_tag^=1;
    }
    void pushupd(long long x,long long v)
    {
        if(v==nulltag||x==0)
        {
            return;
        }
        // printf("pushupd(%lld,%lld)\n",x,v);
        t[x].val=v;
        t[x].sum=1ll*t[x].siz*v;
        t[x].ans=max(v,t[x].sum);
        t[x].maxl=max(0ll,t[x].sum);
        t[x].maxr=max(0ll,t[x].sum);
        t[x].upd_tag=v;
    }
    void pushdown(long long x)
    {
        // printf("pushdown(%lld)\n",x);
        if(t[x].rev_tag)
        {
            pushrev(t[x].l);
            pushrev(t[x].r);
            t[x].rev_tag=0;
        }
        if(t[x].upd_tag!=nulltag)
        {
            pushupd(t[x].l,t[x].upd_tag);
            pushupd(t[x].r,t[x].upd_tag);
            t[x].upd_tag=nulltag;
        }
    }
    void split(long long p,long long v,long long &x,long long &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        pushdown(p);
        if(t[t[p].l].siz+1<=v)
        {
            x=p;
            split(t[p].r,v-t[t[p].l].siz-1,t[p].r,y);
        }
        else
        {
            y=p;
            split(t[p].l,v,x,t[p].l);
        }
        pushup(p);
    }
    long long merge(long long x,long long y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        pushdown(x);
        pushdown(y);
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    void deltree(long long x)
    {
        if(x==0)
        {
            return;
        }
        deltree(t[x].l);
        deltree(t[x].r);
        t[x].l=t[x].r=t[x].sum=t[x].val=t[x].key=0;
        t[x].rev_tag=t[x].siz=t[x].maxl=t[x].maxr=0;
        t[x].ans=-1e18;
        t[x].upd_tag=nulltag;
        s.push(x);
    }
    void push_back(long long v)
    {
        long long x=newnode(v);
        root=merge(root,x);
    }
    void insert(long long pos,vector<long long> v)
    {
        long long x,y;
        split(root,pos,x,y);
        for(long long i:v)
        {
            x=merge(x,newnode(i));
        }
        root=merge(x,y);
    }
    void del(long long l,long long r)
    {
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        root=merge(x,z);
        deltree(y);
    }
    void reverse(long long l,long long r)
    {
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        pushrev(y);
        root=merge(merge(x,y),z);
    }
    void update(long long l,long long r,long long v)
    {
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        // printf("y=%lld\n",y);
        pushupd(y,v);
        root=merge(merge(x,y),z);
    }
    long long getsum(long long l,long long r)
    {
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        long long ans=t[y].sum;
        root=merge(merge(x,y),z);
        return ans;
    }
    long long getans(long long l,long long r)
    {
        // return t[root].ans;
        long long x,y,z;
        split(root,r,x,z);
        split(x,l-1,x,y);
        long long ans=t[y].ans;
        root=merge(merge(x,y),z);
        return ans;
    }
    long long size()
    {
        return t[root].siz;
    }
    bool empty()
    {
        return size()==0;
    }
}t;
char op[100010];
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        long long x;
        scanf("%lld",&x);
        t.push_back(x);
    }
    while(m--)
    {
        scanf("%s",op+1);
        // cerr<<"op"<<op+1<<"\n";
        if(op[1]=='M'&&op[4]=='-')
        {
            printf("%lld\n",t.getans(1,t.size()));
            continue;
        }
        long long l,r;
        scanf("%lld%lld",&l,&r);
        // cerr<<"l="<<l<<" r="<<r<<"\n";
        r+=l-1;
        if(op[1]=='I')
        {
            long long tot=r-l+1;
            vector<long long> v;
            for(long long i=1;i<=tot;i++)
            {
                long long x;
                scanf("%lld",&x);
                v.push_back(x);
            }
            t.insert(l,v);
        }
        else if(op[1]=='D')
        {
            t.del(l,r);
        }
        else if(op[1]=='M')
        {
            long long v;
            scanf("%lld",&v);
            t.update(l,r,v);
        }
        else if(op[1]=='R')
        {
            t.reverse(l,r);
        }
        else if(op[1]=='G')
        {
            printf("%lld\n",t.getsum(l,r));
        }
        // else
        // {
        //     assert(false);
        // }
    }
    // printf("root=%d\n",t.root);
    // for(int i=1;i<=t.size();i++)
    // {
        // printf("id=%d lson=%lld rson=%lld val=%lld sum=%lld maxl=%lld maxr=%lld ans=%lld upd_tag=%lld rev_tag=%lld\n",i,t.t[i].l,t.t[i].r,t.t[i].val,t.t[i].sum,t.t[i].maxl,t.t[i].maxr,t.t[i].ans,t.t[i].upd_tag,t.t[i].rev_tag);
    // }
    // cerr<<"end\n";
    return 0;
}
